import redis
import json
import os
from typing import Optional, Dict, Any
import logging

class RedisCache:
    def __init__(self, redis_hosts: list, redis_port: int = 6379, redis_password: str = None, 
                 redis_db: int = 0, redis_ssl: bool = False):
        self.redis_db = redis_db
        self.redis_password = redis_password
        self.redis_port = redis_port
        self.redis_ssl = redis_ssl
        
        # Create Redis cluster connection
        try:
            self.redis_client = redis.RedisCluster(
                host=redis_hosts[0],
                port=redis_port,
                password=redis_password,
                db=redis_db,
                ssl=redis_ssl,
                decode_responses=True,
                skip_full_coverage_check=True
            )
        except Exception as e:
            logging.error(f"Failed to connect to Redis cluster: {e}")
            raise
    
    def set_user_data(self, user_id: str, data: Dict[str, Any], ttl: int = 3600) -> bool:
        """Store user sensitive data with TTL"""
        try:
            key = f"user:data:{user_id}"
            self.redis_client.setex(key, ttl, json.dumps(data))
            return True
        except Exception as e:
            logging.error(f"Failed to set user data: {e}")
            return False
    
    def get_user_data(self, user_id: str) -> Optional[Dict[str, Any]]:
        """Retrieve user sensitive data"""
        try:
            key = f"user:data:{user_id}"
            data = self.redis_client.get(key)
            return json.loads(data) if data else None
        except Exception as e:
            logging.error(f"Failed to get user data: {e}")
            return None
    
    def delete_user_data(self, user_id: str) -> bool:
        """Delete user sensitive data"""
        try:
            key = f"user:data:{user_id}"
            deleted = self.redis_client.delete(key)
            return deleted > 0
        except Exception as e:
            logging.error(f"Failed to delete user data: {e}")
            return False
    
    def set_session_token(self, session_id: str, token: str, ttl: int = 1800) -> bool:
        """Store session token with TTL"""
        try:
            key = f"session:token:{session_id}"
            self.redis_client.setex(key, ttl, token)
            return True
        except Exception as e:
            logging.error(f"Failed to set session token: {e}")
            return False
    
    def get_session_token(self, session_id: str) -> Optional[str]:
        """Retrieve session token"""
        try:
            key = f"session:token:{session_id}"
            return self.redis_client.get(key)
        except Exception as e:
            logging.error(f"Failed to get session token: {e}")
            return None
    
    def delete_session_token(self, session_id: str) -> bool:
        """Delete session token"""
        try:
            key = f"session:token:{session_id}"
            deleted = self.redis_client.delete(key)
            return deleted > 0
        except Exception as e:
            logging.error(f"Failed to delete session token: {e}")
            return False
    
    def set_api_key(self, user_id: str, api_key: str, ttl: int = 86400) -> bool:
        """Store API key with TTL"""
        try:
            key = f"user:api_key:{user_id}"
            self.redis_client.setex(key, ttl, api_key)
            return True
        except Exception as e:
            logging.error(f"Failed to set API key: {e}")
            return False
    
    def get_api_key(self, user_id: str) -> Optional[str]:
        """Retrieve API key"""
        try:
            key = f"user:api_key:{user_id}"
            return self.redis_client.get(key)
        except Exception as e:
            logging.error(f"Failed to get API key: {e}")
            return None
    
    def delete_api_key(self, user_id: str) -> bool:
        """Delete API key"""
        try:
            key = f"user:api_key:{user_id}"
            deleted = self.redis_client.delete(key)
            return deleted > 0
        except Exception as e:
            logging.error(f"Failed to delete API key: {e}")
            return False

